import { ChatGoogle } from "@langchain/google";
import * as fs from "fs";

const llm = new ChatGoogle({ model: "gemini-3-flash-preview" });

// Load and encode the image
const dataPath = "path/to/image.png";
const data = await fs.readFile(dataPath);
const data64 = data.toString("base64");

// Construct multimodal content
const content: ContentBlock.Standard[] = [
  { type: "text", text: "Describe this image." },
  { type: "image", data: data64, mimeType: "image/png" }
];

// Invoke the model
const result = await llm.invoke(content);
console.log(result.contentBlocks);
